// TypeScript implementation for Type Aliases
interface TypeAliasesPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processTypeAliases(item: TypeAliasesPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processTypeAliases({ id: 1, title: 'Type Aliases', status: 'active' }));

